    {
      "keystrokes": "cat > /tmp/new_autoexec.bat << 'EOF'\n@ECHO OFF\nC:\\WINDOWS\\SMARTDRV.EXE 2048 128\nPROMPT $p$g\nPATH C:\\WINDOWS;C:\\DOS\nSET TEMP=C:\\TEMP\nwin\nEOF\n",
      "duration": 0.5
    },
    {
      "keystrokes": "mcopy -o -i /app/isos/win311.img@@32256 /tmp/new_autoexec.bat ::AUTOEXEC.BAT\n",
      "duration": 2.0
    },
    {
      "keystrokes": "mtype -i /app/isos/win311.img@@32256 ::AUTOEXEC.BAT\n",
      "duration": 1.0
    }
